def now_iso():
    return datetime.utcnow().isoformat(times="seconds") + "Z"


def build_connection_parameters(host, port, vhost, username, password, heartbeat, blocked_connection_timeout):
    credentials = pika.PlainCredentials(username, password)
    return pika.ConnectionParameters(
        host=host,
        port=port,
        virtual_host=vhost,
        credentials=credentials,
        heartbeat=heartbeat,
        blocked_connection_timeout=blocked_connection_timeout,
        connection_attempts=3,
        retry_delay=2,
    )


def ensure_queue(channel, queue_name, durable=True, prefetch_count=1):
    channel.queue_declare(queue=queue_name, durable=durable, arguments=None)
    channel.basic_qos(prefetch_count=prefetch_count)


def create_task_payload(task, task_id=None, meta=None):
    if task_id is None:
        task_id = str(uuid.uuid4())
    payload = {
        "id": task_id,
        "task": task,
        "meta": meta or {},
        "created_at": now_iso(),
    }
    return payload


def publisher(args):
    params = build_connection_parameters(
        args.host,
        args.port,
        args.vhost,
        args.username,
        args.password,
        args.heartbeat,
        args.blocked_connection_timeout,
    )
    connection = pika.BlockingConnection(params)
    channel = connection.channel()
    ensure_queue(channel, args.queue, durable=True)

    count = args.count if args.count is not None else 1
    interval = args.interval if args.interval is not None else 0.0

    sent = 0
    try:
        for i in range(count) if count >= 0 else iter(int, 1):
            task_body = args.message
            if args.json:
                meta = {"sequence": i} if count >= 0 else {}
                payload = create_task_payload(task_body, meta=meta)
                body = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
                content_type = "application/json"
            else:
                body = task_body.encode("utf-8")
                content_type = "text/plain"

            props = pika.BasicProperties(
                delivery_mode=2,
                content_type=content_type,
                message_id=str(uuid.uuid4()),
                timestamp=int(time.time()),
                app_id=args.app_id or "task_publisher",
                headers={"queue": args.queue},
            )

            channel.basic_publish(
                exchange=DEFAULT_EXCHANGE,
                routing_key=args.routing_key or args.queue,
                body=body,
                properties=props,
                mandatory=False,
            )
            sent += 1
            sys.stdout.write(f"published {sent} message(s)\n")
            sys.stdout.flush()

            if interval > 0:
                time.sleep(interval)
    except KeyboardInterrupt:
        pass
    finally:
        try:
            connection.close()
        except Exception:
            pass


def _default_process_task(body_bytes, content_type):
    if content_type == "application/json":
        payload = json.loads(body_bytes.decode("utf-8"))
        task_desc = payload.get("task")
        task_id = payload.get("id")
        return task_id, task_desc, payload
    try:
        text = body_bytes.decode("utf-8")
    except Exception:
        text = repr(body_bytes)
    return None, text, {"task": text}


def consumer(args):
    stop_event = threading.Event()

    def handle_signal(signum, frame):
        stop_event.set()

    signal.signal(signal.SIGINT, handle_signal)
    signal.signal(signal.SIGTERM, handle_signal)

    params = build_connection_parameters(
        args.host,
        args.port,
        args.vhost,
        args.username,
        args.password,
        args.heartbeat,
        args.blocked_connection_timeout,
    )
    connection = pika.BlockingConnection(params)
    channel = connection.channel()
    ensure_queue(channel, args.queue, durable=True, prefetch_count=args.prefetch)

    def on_message(ch, method, properties, body):
        task_id, task_desc, payload = _default_process_task(body, getattr(properties, "content_type", None))
        tag = method.delivery_tag
        try:
            sys.stdout.write(
                f"received delivery_tag={tag} task_id={task_id or '-'} task={task_desc}\n"
            )
            sys.stdout.flush()

            if args.simulate_work:
                seconds = args.work_seconds
                if args.work_from_message and isinstance(payload, dict):
                    meta = payload.get("meta") or {}
                    if isinstance(meta, dict) and isinstance(meta.get("work_seconds"), (int, float)):
                        seconds = float(meta["work_seconds"])
                time.sleep(max(0.0, seconds))

            if args.fail_rate > 0.0:
                import random

                if random.random() < args.fail_rate:
                    raise RuntimeError("simulated processing failure")

            ch.basic_ack(delivery_tag=tag)
            sys.stdout.write(f"acked delivery_tag={tag}\n")
            sys.stdout.flush()
        except Exception as e:
            sys.stderr.write(f"error delivery_tag={tag}: {e}\n")
            sys.stderr.flush()
            if args.requeue_on_fail:
                ch.basic_nack(delivery_tag=tag, requeue=True)
            else:
                ch.basic_nack(delivery_tag=tag, requeue=False)

    consumer_tag = channel.basic_consume(queue=args.queue, on_message_callback=on_message, auto_ack=False)

    try:
        while not stop_event.is_set():
            connection.process_data_events(time_limit=1.0)
    finally:
        try:
            channel.basic_cancel(consumer_tag)
        except Exception:
            pass
        try:
            connection.close()
        except Exception:
            pass


def parse_args(argv):
    parser = argparse.ArgumentParser(
        description="RabbitMQ publisher/consumer using pika (localhost:5672 by default)."
    )
    sub = parser.add_subparsers(dest="mode", required=True)

    def add_common(p):
        p.add_argument("--host", default=os.getenv("RABBITMQ_HOST", DEFAULT_HOST))
        p.add_argument("--port", type=int, default=int(os.getenv("RABBITMQ_PORT", DEFAULT_PORT)))
        p.add_argument("--vhost", default=os.getenv("RABBITMQ_VHOST", DEFAULT_VHOST))
        p.add_argument("--username", default=os.getenv("RABBITMQ_USERNAME", DEFAULT_USERNAME))
        p.add_argument("--password", default=os.getenv("RABBITMQ_PASSWORD", DEFAULT_PASSWORD))
        p.add_argument("--heartbeat", type=int, default=int(os.getenv("RABBITMQ_HEARTBEAT", "60")))
        p.add_argument(
            "--blocked-connection-timeout",
            type=int,
            default=int(os.getenv("RABBITMQ_BLOCKED_TIMEOUT", "30")),
        )
        p.add_argument("--queue", default=os.getenv("RABBITMQ_QUEUE", DEFAULT_QUEUE))
        p.add_argument("--routing-key", default=os.getenv("RABBITMQ_ROUTING_KEY", ""))

    pub = sub.add_parser("publish", help="Publish task messages to a queue.")
    add_common(pub)
    pub.add_argument("message", help="Task message body (string).")
    pub.add_argument("--count", type=int, default=1, help="Number of messages to send. Use -1 for infinite.")
    pub.add_argument("--interval", type=float, default=0.0, help="Seconds between messages.")
    pub.add_argument("--json", action="store_true", help="Send JSON task payload.")
    pub.add_argument("--app-id", default=os.getenv("APP_ID", "task_publisher"))

    con = sub.add_parser("consume", help="Consume and process task messages from a queue.")
    add_common(con)
    con.add_argument("--prefetch", type=int, default=1, help="QoS prefetch count.")
    con.add_argument("--simulate-work", action="store_true", help="Sleep to simulate work.")
    con.add_argument("--work-seconds", type=float, default=1.0, help="Work duration when simulate-work enabled.")
    con.add_argument(
        "--work-from-message",
        action="store_true",
        help="If JSON payload meta.work_seconds exists, use it.",
    )
    con.add_argument("--fail-rate", type=float, default=0.0, help="Simulate failures with probability [0..1].")
    con.add_argument("--requeue-on-fail", action="store_true", help="Requeue message on failure.")

    return parser.parse_args(argv)


